mapper.select:
select model_id, model_name, model_code, api_key, api_url, is_enabled, create_time, update_time
from sys_ai_model
where model_id = #{modelId}

mapper.update:
update sys_ai_model
model_name = #{modelName}, model_code = #{modelCode}, api_key = #{apiKey}, api_url = #{apiUrl}, is_enabled = #{isEnabled}, update_time = CURRENT_TIMESTAMP
where model_id = #{modelId}
